import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { link } from 'decantr/router';
import { Button, icon, Badge } from 'decantr/components';

code.example:
function PropertyCard({ property }) {
  const { div, img, span, h3, p } = tags;
  const occupancyColor = property.occupancyRate >= 90 ? 'success' : property.occupancyRate >= 70 ? 'warning' : 'danger';

  return div({ class: css('estate-card _overflow[hidden]') },
    img({ src: property.image, alt: property.address, class: css('_wfull _h40 _objcover') }),
    div({ class: css('_p4 _flex _col _gap3') },
      div({ class: css('_flex _jcsb _aic') },
        Badge({ variant: 'outline' }, property.type),
        Badge({ variant: property.status === 'active' ? 'success' : 'default' }, property.status)
      ),
      div({},
        h3({ class: css('_heading5 _mb1') }, property.name || property.address),
        p({ class: css('_textsm _fgmuted') }, `${property.city}, ${property.state} ${property.zip}`)
      ),
      div({ class: css('_grid _cols3 _gap2 _pt3 _borderT') },
        div({ class: css('_tc') },
          span({ class: css('_heading4 _block') }, property.units),
          span({ class: css('_textxs _fgmuted') }, 'Units')
        ),
        div({ class: css('_tc') },
          span({ class: css(`_heading4 _block _fg${occupancyColor}`) }, `${property.occupancyRate}%`),
          span({ class: css('_textxs _fgmuted') }, 'Occupied')
        ),
        div({ class: css('_tc') },
          span({ class: css('_heading4 _block') }, `$${property.monthlyRevenue.toLocaleString()}`),
          span({ class: css('_textxs _fgmuted') }, '/month')
        )
      ),
      div({ class: css('_flex _gap2 _pt3') },
        link({ href: `/properties/${property.id}`, class: css('_flex1') },
          Button({ variant: 'primary', class: css('_wfull') }, 'View Property')
        ),
        Button({ variant: 'outline', size: 'icon' }, icon('more-vertical'))
      )
    )
  );
}

