  return link({ href: `/properties/${property.id}`, class: css('estate-card _p4 _flex _col _gap2 _trans _hoverShadow') },
    div({ class: css('_flex _jcsb _aic') },
      h4({ class: css('_heading6') }, property.name || property.address.split(',')[0]),
      Badge({ variant: 'outline', size: 'sm' }, property.type)
